## Duel

排序，后一个打前一个。$O(n\log n)$。

参考用时：5min

```cpp
#include<bits/stdc++.h>
#define For(i,a,b) for(int i=(a);i<=(b);++i)
#define Rof(i,a,b) for(int i=(a);i>=(b);--i)
using namespace std;
const int Maxn=2e5;

int n,a[Maxn+5];

int main()
{
    cin>>n;
    For(i,1,n) cin>>a[i];
    sort(a+1,a+n+1);
    int it=1;
    For(i,2,n) if(a[i]>a[it]) it++;
    cout<<n-it+1<<endl;
    return 0;
}
```

